1	import { Router } from 'express';
2	import { createComment, ForeignKeyError } from '../db/queries.js';
3	
4	const router = Router();
5	
6	router.post('/cards/:id/comments', (req, res, next) => {
7	  const { author, content } = req.body ?? {};
8	
9	  if (!author || !content) {
10	    return res.status(400).json({ error: 'author and content are required' });
11	  }
12	
13	  try {
14	    const comment = createComment(req.params.id, { author, content });
15	    return res.status(201).json(comment);
16	  } catch (err) {
17	    if (err instanceof ForeignKeyError) {
18	      return res.status(404).json({ error: err.message });
19	    }
20	    next(err); // passes to Express error handler → 500
21	  }
22	});
23	
24	export default router;
