1	import { describe, it, before, after } from 'node:test';
2	import assert from 'node:assert/strict';
3	import { mkdirSync, writeFileSync, rmSync, existsSync, readFileSync } from 'node:fs';
4	import { resolve, join, dirname } from 'node:path';
5	import { fileURLToPath } from 'node:url';
6	import { createApp } from '../index.js'; // ← required by every test suite that starts a server
7	
8	const __dirname = dirname(fileURLToPath(import.meta.url));
9	const SERVER_ROOT = resolve(__dirname, '..'); // kanban/server/
10	const ROOT = resolve(SERVER_ROOT, '..'); // kanban/
11	
12	async function startTestServer(app) {
13	  return new Promise((resolvePromise) => {
14	    const server = app.listen(0, () => {
15	      resolvePromise({ server, baseUrl: `http://localhost:${server.address().port}` });
16	    });
17	  });
18	}
19	function stopServer(server) {
20	  return new Promise((resolvePromise) => server.close(resolvePromise));
21	}
