23	// ── Subtask 1: Dependency availability ───────────────────────────────────────
24	
25	describe('Dependencies availability', () => {
26	  const pkg = JSON.parse(readFileSync(join(SERVER_ROOT, 'package.json'), 'utf8'));
27	
28	  it('express can be imported', async () => {
29	    const { default: express } = await import('express');
30	    assert.strictEqual(typeof express, 'function');
31	  });
32	
33	  it('cors can be imported', async () => {
34	    const { default: cors } = await import('cors');
35	    assert.strictEqual(typeof cors, 'function');
36	  });
37	
38	  it('better-sqlite3 can be imported', async () => {
39	    const { default: Database } = await import('better-sqlite3');
40	    assert.strictEqual(typeof Database, 'function');
41	  });
42	
43	  it('ws can be imported', async () => {
44	    const { default: WebSocket } = await import('ws');
45	    assert.ok(typeof WebSocket === 'function' || typeof WebSocket.WebSocket === 'function');
46	  });
