  })

  it('ApiError.data contains the parsed error body', async () => {
    vi.stubGlobal(
      'fetch',
      vi.fn().mockResolvedValue(mockResponse({ error: 'Not Found' }, { status: 404 })),
    )
    let caught
    try {
      await fetchCards()
    } catch (err) {
      caught = err
    }
    expect(caught).toBeInstanceOf(ApiError)
    expect(caught.data).toEqual({ error: 'Not Found' })
  })
})

